WITH active_users AS (
  SELECT DISTINCT user_id FROM sessions WHERE session_date BETWEEN {start_date} AND {end_date}
),
feature_users AS (
  SELECT DISTINCT user_id FROM feature_usage WHERE feature_name = {feature_name} AND event_date BETWEEN {start_date} AND {end_date}
),
metrics AS (
  SELECT COUNT(DISTINCT au.user_id) AS total_active, COUNT(DISTINCT fu.user_id) AS feature_users FROM active_users au LEFT JOIN feature_users fu ON au.user_id = fu.user_id
)
SELECT total_active, feature_users, feature_users * 100.0 / NULLIF(total_active, 0) AS adoption_rate FROM metrics

WITH active_users AS (
  SELECT DISTINCT user_id FROM sessions WHERE session_date BETWEEN {start_date} AND {end_date}
),
feature_usage_per_user AS (
  SELECT user_id, COUNT(DISTINCT feature_name) AS features_used FROM feature_usage WHERE event_date BETWEEN {start_date} AND {end_date} GROUP BY user_id
),
metrics AS (
  SELECT AVG(COALESCE(fup.features_used, 0)) AS avg_breadth FROM active_users au LEFT JOIN feature_usage_per_user fup ON au.user_id = fup.user_id
)
SELECT avg_breadth FROM metrics

WITH daily_active AS (
  SELECT DATE_TRUNC('day', session_date) AS day, COUNT(DISTINCT user_id) AS dau FROM sessions WHERE session_date BETWEEN {start_date} AND {end_date} GROUP BY 1
),
monthly_active AS (
  SELECT DATE_TRUNC('month', session_date) AS month, COUNT(DISTINCT user_id) AS mau FROM sessions WHERE session_date BETWEEN DATEADD(day, -30, {end_date}) AND {end_date} GROUP BY 1
),
metrics AS (
  SELECT AVG(d.dau) AS avg_dau, AVG(m.mau) AS avg_mau FROM daily_active d CROSS JOIN monthly_active m
)
SELECT avg_dau, avg_mau, avg_dau * 100.0 / NULLIF(avg_mau, 0) AS stickiness_ratio FROM metrics

WITH sessions AS (
  SELECT session_id, user_id, MIN(event_time) AS session_start, MAX(event_time) AS session_end FROM event_logs WHERE event_date BETWEEN {start_date} AND {end_date} GROUP BY session_id, user_id
),
page_depth AS (
  SELECT session_id, COUNT(DISTINCT page_path) AS pages FROM event_logs WHERE event_type = 'page_view' AND event_date BETWEEN {start_date} AND {end_date} GROUP BY session_id
),
action_depth AS (
  SELECT session_id, COUNT(DISTINCT action_name) AS actions FROM event_logs WHERE event_type = 'action' AND event_date BETWEEN {start_date} AND {end_date} GROUP BY session_id
),
metrics AS (
  SELECT AVG(COALESCE(pd.pages, 0) + COALESCE(ad.actions, 0)) AS avg_depth FROM sessions s LEFT JOIN page_depth pd ON s.session_id = pd.session_id LEFT JOIN action_depth ad ON s.session_id = ad.session_id
)
SELECT avg_depth FROM metrics

WITH users_sent AS (
  SELECT DISTINCT user_id FROM notification_events WHERE event_date BETWEEN {start_date} AND {end_date}
),
users_opted_out AS (
  SELECT DISTINCT user_id FROM notification_events WHERE event_type = 'opt_out' AND event_date BETWEEN {start_date} AND {end_date}
),
metrics AS (
  SELECT COUNT(DISTINCT us.user_id) AS total_sent, COUNT(DISTINCT uo.user_id) AS opted_out FROM users_sent us LEFT JOIN users_opted_out uo ON us.user_id = uo.user_id
)
SELECT total_sent, opted_out, opted_out * 100.0 / NULLIF(total_sent, 0) AS opt_out_rate FROM metrics
